const pinflight=require("promise-inflight"),spawn=require("./spawn.js"),{LRUCache:LRUCache}=require("lru-cache"),revsCache=new LRUCache({max:100,ttl:3e5}),linesToRevs=require("./lines-to-revs.js");module.exports=async(e,s={})=>{if(!s.noGitRevCache){const s=revsCache.get(e);if(s)return s}return pinflight(`ls-remote:${e}`,()=>spawn(["ls-remote",e],s).then(({stdout:e})=>linesToRevs(e.trim().split("\n"))).then(s=>(revsCache.set(e,s),s)))};